const src = $input.first().json || {};
const raw = [src.chatInput, src.text, src.message, src.prompt, src.input].find((v) => typeof v === 'string' && v.trim()) || JSON.stringify(src);

return [{
  json: {
    ...src,
    refactorRequest: raw.trim(),
    chatInput: raw.trim()
  }
}];

const src = $input.first().json || {};
const raw = String(src.refactorRequest || src.chatInput || src.text || src.message || src.prompt || src.input || '').trim();
const urlMatch = raw.match(/https?:\/\/github\.com\/([^/\s?#]+)\/([^/\s?#]+)(?:\.git)?(?:[/?#]|$)/i);
const sanitized = raw.replace(/https?:\/\/\S+/gi, ' ');
const shorthandMatch = sanitized.match(/(?:^|[\s"'`(])([A-Za-z0-9-]+)\/([A-Za-z0-9_.-]+)(?=[\s"'`),.!?]|$)/);
const match = urlMatch || shorthandMatch;
const cleanSegment = (value) => String(value || '').replace(/[)\],.!?;:'"`]+$/g, '');
const repositoryOwner = match ? cleanSegment(match[1]) : '';
const repositoryName = match ? cleanSegment(match[2]).replace(/\.git$/i, '') : '';
const repositoryTarget = repositoryOwner && repositoryName ? `${repositoryOwner}/${repositoryName}` : '';
const needsClarification = !repositoryTarget;
const clarificationMessage = 'Please provide a GitHub repository URL or owner/repo string, for example https://github.com/openai/openai or openai/openai.';
const requestedAction = /\brefactor(?:\s+the\s+repo)?\b/i.test(raw)
  ? 'refactor'
  : /\b(review|inspect|audit|analy[sz]e)\b/i.test(raw)
    ? 'inspect'
    : 'refactor';

return [{
  json: {
    ...src,
    repositoryOwner,
    repositoryName,
    repositoryTarget,
    requestedAction,
    needsClarification,
    clarificationMessage,
    refactorRequest: repositoryTarget ? `${raw}\n\nTarget repository: ${repositoryTarget}\nRequested action: ${requestedAction}` : raw,
    chatInput: raw
  }
}];

const src = $input.first().json || {};
return [{
  json: {
    text: src.clarificationMessage || 'Please provide a GitHub repository URL or owner/repo string before I can inspect it.',
    needsClarification: true
  }
}];

const src = $('Validate Repository Target').first().json || {};
const lookup = $input.first().json || {};
const lookupFailed = Boolean(lookup.error);
const repositoryLookup = lookupFailed
  ? null
  : {
      fullName: lookup.full_name ?? lookup.fullName ?? src.repositoryTarget ?? '',
      private: lookup.private ?? null,
      archived: lookup.archived ?? null,
      disabled: lookup.disabled ?? null,
      defaultBranch: lookup.default_branch ?? lookup.defaultBranch ?? null,
      description: lookup.description ?? null,
      language: lookup.language ?? null,
      htmlUrl: lookup.html_url ?? lookup.htmlUrl ?? null
    };

return [{
  json: {
    ...src,
    repositoryLookup,
    repositoryLookupError: lookupFailed ? lookup.error : null,
    repositoryLookupStatus: lookupFailed ? 'failed' : 'ok'
  }
}];

const src = $input.first().json || {};
return [{
  json: {
    text: `I could not access ${src.repositoryTarget || 'the requested repository'}. It may be private, unavailable, or the credential may not have access. Provide a reachable repository or the relevant files directly.`,
    repositoryUnavailable: true
  }
}];
